  90→void ftKb_NsSpecialNHold_Anim(HSD_GObj* gobj)
  91→{
  92→    Fighter* fp = GET_FIGHTER(gobj);
  93→    int flash_timer_min = fp->mv.kb.specialn_ns.frames_to_loop_charge_ground;
  94→    if (flash_timer_min != 0) {
  95→        fp->mv.kb.specialn_ns.frames_to_loop_charge_ground =
  96→            flash_timer_min - 1;
  97→    }
  98→    if (fp->fv.kb.ns_flash_gobj == NULL) {
  99→        int flash_timer_delay =
 100→            fp->mv.kb.specialn_ns.frames_to_loop_charge_air;
 101→        if (flash_timer_delay != 0) {
 102→            fp->mv.kb.specialn_ns.frames_to_loop_charge_air =
 103→                flash_timer_delay - 1;
 104→        }
 105→    }
 106→    if (fp->fv.kb.ns_flash_gobj == NULL) {
 107→        if (fp->mv.kb.specialn_ns.frames_to_loop_charge_ground <= 0 &&
 108→            fp->mv.kb.specialn_ns.frames_to_loop_charge_air <= 0)
 109→        {
 110→            Fighter_ChangeMotionState(gobj, ftKb_MS_NsSpecialNEnd, 0, 0, 1, 0,
 111→                                      NULL);
 112→            return;
 113→        }
 114→        if (fp->motion_id != ftKb_MS_NsSpecialNHold1) {
 115→            Fighter_ChangeMotionState(gobj, ftKb_MS_NsSpecialNHold1, 0,
 116→                                      fp->cur_anim_frame, 1, 0, NULL);
 117→        }
 118→    } else {
 119→        if (it_802AA7E4(fp->fv.kb.ns_flash_gobj) != gobj) {
 120→            fp->fv.kb.ns_flash_gobj = NULL;
 121→            return;
 122→        }
 123→        if (it_802AA7F0(fp->fv.kb.ns_flash_gobj) == 1 &&
 124→            fp->motion_id != ftKb_MS_NsSpecialNHold1)
 125→        {
 126→            Fighter_ChangeMotionState(gobj, ftKb_MS_NsSpecialNHold1, 0,
 127→                                      fp->cur_anim_frame, 1, 0, NULL);
 128→        }
 129→    }
 130→}
